private struct StravaTabHost<Content: View>: View {
    let title: String
    let icon: String
    @ViewBuilder var content: () -> Content
    var body: some View { content() }
}

private enum StravaScreenFactory {
    @ViewBuilder
    static func screen(for tab: String) -> some View {
        switch tab.lowercased() {
        case let t where t.contains("fil") || t.contains("home") || t.contains("accueil"):
            StravaFeedScreen()
        case let t where t.contains("map") || t.contains("carte"):
            StravaMapScreen()
        case let t where t.contains("group") || t.contains("vous") || t.contains("profil"):
            StravaProfileScreen()
        default:
            StravaGenericListScreen(title: tab)
        }
    }
}
